// python3
from typing import Optional
import sys
from collections import defaultdict

class Node:
    def __init__(self, x):
        self.val = x
        self.next = None

class Solution:
    def findMiddle(self, head: Optional[Node]) -> int:
        if not head:
            return sys.stdin.readline().strip()

        slow = head
        fast = head
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
        return slow.val if slow else 0

if __name__ == '__main__':
    head = Node(1)
    head.next = Node(2)
    head.next.next = Node(3)
    head.next.next.next = Node(4)
    head.next.next.next.next = Node(5)
    s = Solution()
    print(s.findMiddle(head))
